function setupFormValidation(formName) {
  $.validator.addMethod("regex", function (value, element, regexp) {
    return this.optional(element) || regexp.test(value);
  }, "Please check your input.");
  $.validator.addMethod("selectValidEntry", function (value, element, arg) {
    return value !== "NA" && value !== "";
  }, "Please select a valid answer from the dropdown list.");
  $.validator.addMethod("needsSelection", function (value, element) {
    const count = $(element).find("option:selected").length;
    return count > 0;
  });
  $("#race").bsMultiSelect({
    useCss: true
  });
  $("form[name='".concat(formName, "']")).validate({
    // Specify validation rules
    rules: {
      // The key name on the left side is the name attribute
      // of an input field. Validation rules are defined
      // on the right side

      attritionAnswer: {
        required: true,
        regex: /^\s*I will answer open-ended questions.\s*$/ // \s* : any number of white spaces
      },
      whatTested: {
        required: true,
        minlength: 5
      },
      strategies: {
        required: true,
        minlength: 5
      },
      estimatedPerformance: {
        required: true,
        min: 1,
        max: 100,
        digits: true
      },
      seriousness: {
        required: true,
        min: 1,
        max: 100,
        digits: true
      },
      interruption: {
        required: true,
        selectValidEntry: true
      },
      participatedBefore: {
        required: true,
        selectValidEntry: true
      },
      issues: {
        required: true,
        minlength: 2
      },
      comments: {
        required: false
      },
      age: {
        required: true,
        min: 18,
        max: 120,
        digits: true
      },
      race: {
        needsSelection: true
      },
      sex: {
        required: true,
        selectValidEntry: true
      },
      gender: {
        required: true,
        minlength: 2
      }
    },
    messages: {
      attritionAnswer: {
        required: "Please enter the highlighted text, including the period.",
        regex: "Please enter the highlighted text, including the period."
      },
      age: {
        required: "Please enter your age",
        min: "Please enter a valid adult age",
        max: "Please enter a valid adult age"
      },
      race: {
        needsSelection: "Please select at least one race"
      },
      sex: {
        required: "Please select your sex"
      },
      gender: {
        required: "Please enter your self-identifed gender"
      }
    },
    ignore: ':hidden:not("#race")',
    // necessary due to bsMultiSelect

    // Highlight on error
    highlight: function highlight(element, errorClass, validClass) {
      $(element).addClass("is-invalid");
    },
    // Remove error highlighting
    unhighlight: function unhighlight(element, errorClass, validClass) {
      $(element).removeClass("is-invalid");
    }
  });
  $.validator.addClassRules("selectValidEntry", {
    selectValidEntry: true
  });
}
function getFormData(formId) {
  const inputs = $("".concat(formId, " :input"));
  let formData = {};
  for (const input of inputs) {
    if (input.name === "") continue;
    formData[input.name] = $(input).val();
  }
  return formData;
}
function initializeFormData(data) {
  if (data === null) {
    return;
  }
  // Assuming that each key is actually an input field id
  for (const [key, val] of Object.entries(data)) {
    $("#".concat(key)).val(val);
  }
}
function generateCompletionCode(prefix, suffix) {
  let code = "";
  for (const i of _.range(0, 10)) {
    let this_num = _.random(0, 9);
    let this_char = this_num.toString();
    code = code + this_char;
  }
  code = "".concat(code, "-").concat(prefix, "-");
  for (let i of _.range(0, 10)) {
    let this_num = _.random(0, 9);
    let this_char = this_num.toString();
    code = code + this_char;
  }
  code = "".concat(code, "-").concat(suffix);
  return code;
}
